const cx = (...args) => args.filter(Boolean).join(" ");

const audioBufferToWavBlob=(buffer)=>{const numChannels=1,sampleRate=buffer.sampleRate,length=buffer.length*numChannels*2+44,ab=new ArrayBuffer(length),view=new DataView(ab);let off=0;const writeStr=(s)=>{for(let i=0;i<s.length;i++)view.setUint8(off++,s.charCodeAt(i))};writeStr("RIFF");view.setUint32(off,36+buffer.length*2,true);off+=4;writeStr("WAVE");writeStr("fmt ");view.setUint32(off,16,true);off+=4;view.setUint16(off,1,true);off+=2;view.setUint16(off,numChannels,true);off+=2;view.setUint32(off,sampleRate,true);off+=4;view.setUint32(off,sampleRate*2,true);off+=4;view.setUint16(off,2,true);off+=2;view.setUint16(off,16,true);off+=2;writeStr("data");view.setUint32(off,buffer.length*2,true);off+=4;const data=buffer.getChannelData(0);for(let i=0;i<buffer.length;i++){const s=Math.max(-1,Math.min(1,data[i]));view.setInt16(off,s<0?s*0x8000:s*0x7FFF,true);off+=2}return new Blob([ab],{type:"audio/wav"})};

const synthesizeVoiceBlob=async(durationSec)=>{const sampleRate=22050,dur=Math.max(1,Math.min(durationSec,60)),numSamples=Math.floor(dur*sampleRate),Ctx=window.OfflineAudioContext||window.webkitOfflineAudioContext;if(!Ctx)throw new Error("unavailable");const ctx=new Ctx(1,numSamples,sampleRate),noiseBuf=ctx.createBuffer(1,numSamples,sampleRate),noise=noiseBuf.getChannelData(0);for(let i=0;i<numSamples;i++)noise[i]=(Math.random()*2-1)*0.3;const src=ctx.createBufferSource();src.buffer=noiseBuf;const filter=ctx.createBiquadFilter();filter.type="bandpass";filter.frequency.value=900;filter.Q.value=1.2;const gain=ctx.createGain();gain.gain.setValueAtTime(0,0);for(let t=0;t<dur;t+=0.28){gain.gain.linearRampToValueAtTime(0.25,t+0.06);gain.gain.linearRampToValueAtTime(0.05,t+0.22)}gain.gain.linearRampToValueAtTime(0,dur);src.connect(filter).connect(gain).connect(ctx.destination);src.start(0);const rendered=await ctx.startRendering();return audioBufferToWavBlob(rendered)};

const useVoiceRecorder=({lang="en"}={})=>{const[voiceUrl,setVoiceUrl]=useState(null),[isRecording,setIsRecording]=useState(false),[duration,setDuration]=useState(0),[isSynthetic,setIsSynthetic]=useState(false),[generating,setGenerating]=useState(false),recorderRef=useRef(null),timerRef=useRef(null),chunksRef=useRef([]),streamRef=useRef(null),startTimeRef=useRef(0),syntheticRef=useRef(false);useEffect(()=>()=>{if(timerRef.current)clearInterval(timerRef.current);if(streamRef.current)streamRef.current.getTracks().forEach(t=>t.stop());if(voiceUrl)URL.revokeObjectURL(voiceUrl)},[]);const start=async()=>{startTimeRef.current=Date.now();setDuration(0);setIsRecording(true);setIsSynthetic(false);syntheticRef.current=false;timerRef.current=setInterval(()=>{setDuration(Math.floor((Date.now()-startTimeRef.current)/1000))},250);try{if(!navigator.mediaDevices?.getUserMedia)throw new Error("unavailable");const stream=await navigator.mediaDevices.getUserMedia({audio:true});streamRef.current=stream;const mime=MediaRecorder.isTypeSupported("audio/webm;codecs=opus")?"audio/webm;codecs=opus":"audio/webm",rec=new MediaRecorder(stream,{mimeType:mime});chunksRef.current=[];rec.ondataavailable=e=>{if(e.data.size>0)chunksRef.current.push(e.data)};rec.onstop=()=>{const blob=new Blob(chunksRef.current,{type:mime});setVoiceUrl(URL.createObjectURL(blob));stream.getTracks().forEach(t=>t.stop());streamRef.current=null};rec.start();recorderRef.current=rec}catch(err){syntheticRef.current=true;setIsSynthetic(true)}};const stop=async()=>{if(timerRef.current){clearInterval(timerRef.current);timerRef.current=null}setIsRecording(false);const finalDuration=Math.max(1,Math.floor((Date.now()-startTimeRef.current)/1000));setDuration(finalDuration);if(syntheticRef.current){setGenerating(true);try{const blob=await synthesizeVoiceBlob(finalDuration);setVoiceUrl(URL.createObjectURL(blob))}catch(e){}finally{setGenerating(false)}}else if(recorderRef.current&&recorderRef.current.state!=="inactive"){recorderRef.current.stop()}};const reset=()=>{if(voiceUrl)URL.revokeObjectURL(voiceUrl);setVoiceUrl(null);setDuration(0);setIsSynthetic(false);syntheticRef.current=false};return{voiceUrl,isRecording,duration,isSynthetic,generating,start,stop,reset}};

const fmtDuration=(s)=>{const m=Math.floor(s/60),sec=s%60;return`${m}:${sec.toString().padStart(2,"0")}`};

const VoicePlayer=({url,duration,onDelete,compact=false,synthetic=false})=>{const audioRef=useRef(null),[playing,setPlaying]=useState(false);const toggle=()=>{if(!audioRef.current)return;if(playing)audioRef.current.pause();else audioRef.current.play()};useEffect(()=>{const a=audioRef.current;if(!a)return;const onPlay=()=>setPlaying(true),onEnd=()=>setPlaying(false);a.addEventListener("play",onPlay);a.addEventListener("pause",onEnd);a.addEventListener("ended",onEnd);return()=>{a.removeEventListener("play",onPlay);a.removeEventListener("pause",onEnd);a.removeEventListener("ended",onEnd)}},[]);return(<div className={cx("flex items-center gap-2 rounded-full px-2.5 py-1",compact?"":"py-1.5")} style={{background:T.accentSft,border:`1px solid ${T.accent}30`}}><audio ref={audioRef} src={url} preload="metadata"/><button onClick={toggle} className="w-6 h-6 rounded-full flex items-center justify-center" style={{background:T.accent,color:"#fff"}}>{playing?<Pause size={11}/>:<Play size={11} style={{marginLeft:1}}/>}</button><div className="flex items-center gap-1.5"><div className="flex items-end gap-[2px]" style={{height:10}}>{[3,6,4,8,5,7,4,6,3,5].map((h,i)=><div key={i} style={{width:2,height:h,background:T.accent,opacity:0.6,borderRadius:1}}/>)}</div><span className="text-[10px] tabular-nums" style={{color:T.inkSoft,fontWeight:600}}>{duration!=null?fmtDuration(duration):""}</span></div>{synthetic&&<span className="text-[8.5px] px-1.5 py-0.5 rounded" style={{background:T.amberBg,color:T.amber,fontWeight:700}}>DEMO</span>}{onDelete&&<button onClick={onDelete} className="w-5 h-5 rounded-full flex items-center justify-center" style={{color:T.inkMute}}><Trash2 size={10}/></button>}</div>)};

