const suggestNextPosition=(room)=>{const ts=room?.turnSchedule;if(!ts?.active||!ts.rotationPlan?.length)return null;const restricted=new Set(ts.restrictedPositions||[]),plan=ts.rotationPlan;if(!ts.lastPosition)return plan.find(p=>!restricted.has(p))||null;let idx=plan.indexOf(ts.lastPosition);for(let step=1;step<=plan.length;step++){const nextIdx=(idx+step)%plan.length;if(!restricted.has(plan[nextIdx]))return plan[nextIdx]}return null};
const minutesUntilTurn=(room)=>{if(!room?.turnSchedule?.active||!room.turnSchedule.lastTurnedAt)return null;const elapsedMin=(Date.now()-room.turnSchedule.lastTurnedAt)/60000;return Math.round((room.turnSchedule.intervalMin||TURN_INTERVAL_MIN)-elapsedMin)};
