const AUDIT=[];let __auditId=1;
const auditLog=(event)=>{const e={id:"AU-"+String(__auditId++).padStart(6,"0"),ts:Date.now(),...event};AUDIT.unshift(e);if(AUDIT.length>200)AUDIT.length=200};

const anonContext=(patient)=>{if(!patient)return"Adult inpatient · general medical care";const ageBand=patient.age==null?"adult":patient.age<18?"pediatric patient":patient.age<40?"young adult":patient.age<65?"middle-aged adult":"older adult";const d=(patient.diagnosis||"").toLowerCase();const careCategory=/post|surger|cholecyst|lap\./.test(d)?"post-surgical recovery":/fall/.test(d)?"post-fall observation":/diabet|t2dm/.test(d)?"diabetes-related care":/wound|ulcer/.test(d)?"wound care":"general medical care";return`${ageBand} · ${careCategory}`};

