const playNotificationChime=()=>{try{const Ctx=window.AudioContext||window.webkitAudioContext;if(!Ctx)return;const ctx=new Ctx();const tone=(freq,when,dur,vol=0.15)=>{const osc=ctx.createOscillator(),gain=ctx.createGain();osc.type="sine";osc.frequency.value=freq;osc.connect(gain).connect(ctx.destination);gain.gain.setValueAtTime(0,ctx.currentTime+when);gain.gain.linearRampToValueAtTime(vol,ctx.currentTime+when+0.02);gain.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+when+dur);osc.start(ctx.currentTime+when);osc.stop(ctx.currentTime+when+dur+0.05)};tone(880,0,0.15);tone(1175,0.13,0.20);setTimeout(()=>ctx.close&&ctx.close(),600)}catch(e){}};

const IDLE_TIMEOUT_MS=90*1000;
const useIdleLock=(active,onLock)=>{const timer=useRef(null);useEffect(()=>{if(!active)return;const reset=()=>{clearTimeout(timer.current);timer.current=setTimeout(()=>{auditLog({actor:"system",action:"auto_lock",note:"idle 90s"});onLock()},IDLE_TIMEOUT_MS)};reset();const evts=["mousedown","keydown","scroll","touchstart"];evts.forEach(e=>window.addEventListener(e,reset));return()=>{clearTimeout(timer.current);evts.forEach(e=>window.removeEventListener(e,reset))}},[active,onLock])};

const LockScreen=({onUnlock,reason="Session auto-locked after inactivity"})=>{const[pin,setPin]=useState(""),[err,setErr]=useState(false);const trySubmit=(newPin)=>{if(newPin.length===4){if(newPin==="1234"){auditLog({actor:"user",action:"unlock",note:"PIN accepted"});onUnlock()}else{auditLog({actor:"user",action:"unlock_failed"});setErr(true);setTimeout(()=>{setPin("");setErr(false)},800)}}};return(<div className="fixed inset-0 z-[60] flex items-center justify-center p-6" style={{background:"rgba(14,34,51,0.96)",backdropFilter:"blur(20px)"}}><div className="text-center text-white max-w-sm w-full"><div className="mx-auto w-20 h-20 rounded-2xl flex items-center justify-center mb-5" style={{background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.15)"}}><Lock size={32}/></div><div className="text-[10px] uppercase tracking-[0.3em] opacity-70 mb-3">Session locked</div><div className="font-display text-2xl mb-2" style={{fontWeight:500}}>Re-enter your PIN</div><div className="text-xs opacity-70 mb-8">{reason}</div><div className={cx("flex gap-2 justify-center mb-6",err&&"animate-shake")}>{[0,1,2,3].map(i=><div key={i} className="w-12 h-14 rounded-xl flex items-center justify-center text-2xl" style={{background:"rgba(255,255,255,0.06)",border:`1px solid ${err?"#ef4444":pin.length===i?T.accent:"rgba(255,255,255,0.15)"}`}}>{pin[i]?"•":""}</div>)}</div><div className="grid grid-cols-3 gap-2 max-w-xs mx-auto">{["1","2","3","4","5","6","7","8","9","","0","⌫"].map((d,i)=><button key={i} disabled={!d} onClick={()=>{if(d==="⌫")setPin(p=>p.slice(0,-1));else if(d&&pin.length<4){const np=pin+d;setPin(np);trySubmit(np)}}} className="aspect-square rounded-xl text-xl disabled:opacity-0" style={{background:"rgba(255,255,255,0.08)",color:"#fff",border:d?"1px solid rgba(255,255,255,0.12)":"none"}}>{d}</button>)}</div><div className="mt-6 text-[10px] opacity-60">Demo PIN: 1234</div></div></div>)};

const BedsideAuth=({onSuccess,onBackHome})=>{const[step,setStep]=useState("qr"),[pin,setPin]=useState(""),[err,setErr]=useState(false);const trySubmit=(newPin)=>{if(newPin.length===4){if(newPin==="1234"){auditLog({actor:"patient",action:"session_start"});onSuccess()}else{setErr(true);setTimeout(()=>{setPin("");setErr(false)},800)}}};return(<div className="min-h-screen flex items-center justify-center p-6 relative" style={{background:T.bg}}>{onBackHome&&<button onClick={onBackHome} className="absolute top-4 left-4 z-10 px-3.5 py-2 rounded-full inline-flex items-center gap-1.5" style={{background:"#fff",border:`1px solid ${T.line}`}}><ArrowLeft size={13} style={{color:T.inkSoft}}/><Home size={13} style={{color:T.inkSoft}}/><span className="text-[11px]" style={{color:T.ink,fontWeight:600}}>Back to Home</span></button>}<Card padding="p-8" className="max-w-md w-full"><Logo size="lg"/>{step==="qr"&&<div className="mt-8 text-center"><div className="mx-auto w-24 h-24 rounded-2xl flex items-center justify-center mb-4" style={{background:T.cardWarm,border:`1px solid ${T.line}`}}><QrCode size={48} style={{color:T.ink}}/></div><div className="text-[11px] uppercase tracking-[0.25em] mb-2" style={{color:T.accent,fontWeight:600}}>Step 1 · Bedside QR</div><h2 className="font-display text-2xl mb-2" style={{color:T.ink,fontWeight:500}}>Scan the QR at your bedside</h2><p className="text-xs mb-6" style={{color:T.inkSoft}}>Each session is bound to your room. No download. No account.</p><Btn variant="dark" size="lg" className="w-full" onClick={()=>setStep("pin")}><QrCode size={16}/> Simulate QR scan</Btn></div>}{step==="pin"&&<div className="mt-8 text-center"><div className="text-[11px] uppercase tracking-[0.25em] mb-2" style={{color:T.accent,fontWeight:600}}>Step 2 · Bedside PIN</div><h2 className="font-display text-2xl mb-2" style={{color:T.ink,fontWeight:500}}>Enter your 4-digit bedside PIN</h2><p className="text-xs mb-6" style={{color:T.inkSoft}}>Given by your nurse · Demo: 1234</p><div className={cx("flex gap-2 justify-center mb-6",err&&"animate-shake")}>{[0,1,2,3].map(i=><div key={i} className="w-12 h-14 rounded-xl flex items-center justify-center text-2xl" style={{background:T.cardWarm,color:T.ink,border:`1px solid ${err?T.red:pin.length===i?T.accent:T.line}`}}>{pin[i]?"•":""}</div>)}</div><div className="grid grid-cols-3 gap-2 max-w-xs mx-auto">{["1","2","3","4","5","6","7","8","9","","0","⌫"].map((d,i)=><button key={i} disabled={!d} onClick={()=>{if(d==="⌫")setPin(p=>p.slice(0,-1));else if(d&&pin.length<4){const np=pin+d;setPin(np);trySubmit(np)}}} className="aspect-square rounded-xl text-xl disabled:opacity-0" style={{background:"#fff",color:T.ink,border:d?`1px solid ${T.line}`:"none"}}>{d}</button>)}</div></div>}</Card></div>)};

const StaffLoginScreen=({role,onSuccess,onCancel})=>{const[staffId,setStaffId]=useState(""),[pin,setPin]=useState(""),[err,setErr]=useState(false),[loading,setLoading]=useState(false),[step,setStep]=useState("id");const roleConfig={nurse:{label:"Nurse Login",sub:"Staff Nurse Access",c:T.indigo,ic:Stethoscope,badge:"Mobile request queue · AI clinical co-pilot"},charge:{label:"Charge Nurse Login",sub:"Unit Charge Access",c:T.gold,ic:LayoutDashboard,badge:"Live heatmap · workload balancing"},leadership:{label:"Leadership Login",sub:"Executive Access",c:T.ink,ic:BarChart3,badge:"KPI dashboard · AI insights"}}[role]||{label:"Login",sub:"",c:T.ink,ic:KeyRound,badge:""};const Ic=roleConfig.ic;const trySubmit=(newPin)=>{if(newPin.length===4){setLoading(true);setTimeout(()=>{if(newPin==="1234"){auditLog({actor:role,action:"session_start",note:`${staffId||role.toUpperCase()} authenticated`});onSuccess({staffId:staffId||`${role.toUpperCase()}-USER`,role})}else{auditLog({actor:role,action:"login_failed"});setErr(true);setLoading(false);setTimeout(()=>{setPin("");setErr(false)},800)}},400)}};return(<div className="min-h-screen flex items-center justify-center p-6 relative" style={{background:T.bg}}>{onCancel&&<button onClick={onCancel} className="absolute top-4 left-4 z-10 px-3.5 py-2 rounded-full inline-flex items-center gap-1.5" style={{background:"#fff",border:`1px solid ${T.line}`}}><ArrowLeft size={13} style={{color:T.inkSoft}}/><Home size={13} style={{color:T.inkSoft}}/><span className="text-[11px]" style={{color:T.ink,fontWeight:600}}>Back to Home</span></button>}<Card padding="p-8" className="max-w-md w-full"><Logo size="lg"/><div className="mt-7"><div className="flex items-center gap-3 mb-2"><div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{background:`${roleConfig.c}15`}}><Ic size={18} style={{color:roleConfig.c}}/></div><div><div className="text-[10px] uppercase tracking-[0.22em]" style={{color:roleConfig.c,fontWeight:700}}>{roleConfig.sub}</div><div className="font-display text-xl" style={{color:T.ink,fontWeight:500}}>{roleConfig.label}</div></div></div><div className="text-[11px] mt-2 inline-flex items-center gap-1.5 px-2 py-1 rounded-full" style={{background:T.greenBg,color:T.green,fontWeight:600}}><ShieldCheck size={11}/> SSO · MFA · 90s auto-lock</div></div>{step==="id"&&<div className="mt-6"><label className="text-[10px] uppercase tracking-wider block mb-1.5" style={{color:T.inkMute,fontWeight:600}}>Staff ID</label><input type="text" value={staffId} onChange={e=>setStaffId(e.target.value)} placeholder="e.g. SFHP-1234" className="w-full rounded-xl px-4 py-3 text-sm focus:outline-none mb-4" style={{background:T.cardWarm,color:T.ink,border:`1px solid ${T.line}`}} autoFocus/><Btn variant="dark" size="lg" className="w-full" onClick={()=>setStep("pin")} disabled={!staffId.trim()}>Continue <ChevronRight size={14}/></Btn>{onCancel&&<button onClick={onCancel} className="w-full mt-3 text-[11px] py-2 rounded-full" style={{color:T.inkSoft,border:`1px solid ${T.line}`}}>Cancel</button>}<div className="mt-4 text-[10px] flex items-center gap-1.5" style={{color:T.inkMute}}><KeyRound size={11}/> Demo: any Staff ID + PIN 1234</div></div>}{step==="pin"&&<div className="mt-6"><button onClick={()=>setStep("id")} className="text-[11px] inline-flex items-center gap-1 mb-3" style={{color:T.inkSoft}}><ChevronLeft size={11}/> {staffId}</button><label className="text-[10px] uppercase tracking-wider block mb-2" style={{color:T.inkMute,fontWeight:600}}>Enter 4-digit PIN</label><div className={cx("flex gap-2 justify-center mb-5",err&&"animate-shake")}>{[0,1,2,3].map(i=><div key={i} className="w-12 h-14 rounded-xl flex items-center justify-center text-2xl" style={{background:T.cardWarm,color:T.ink,border:`1px solid ${err?T.red:pin.length===i?roleConfig.c:T.line}`}}>{pin[i]?"•":""}</div>)}</div><div className="grid grid-cols-3 gap-2 max-w-xs mx-auto">{["1","2","3","4","5","6","7","8","9","","0","⌫"].map((d,i)=><button key={i} disabled={!d||loading} onClick={()=>{if(d==="⌫")setPin(p=>p.slice(0,-1));else if(d&&pin.length<4){const np=pin+d;setPin(np);trySubmit(np)}}} className="aspect-square rounded-xl text-xl disabled:opacity-0" style={{background:"#fff",color:T.ink,border:d?`1px solid ${T.line}`:"none"}}>{d}</button>)}</div>{loading&&<div className="mt-4 text-center text-[11px]" style={{color:T.inkSoft}}><Loader2 size={11} className="animate-spin inline mr-1"/> Authenticating...</div>}{err&&!loading&&<div className="mt-3 text-center text-[11px]" style={{color:T.red}}>Incorrect PIN — try again</div>}<div className="mt-4 text-[10px] text-center" style={{color:T.inkMute}}>Demo PIN: 1234</div></div>}</Card></div>)};

