{(()=>{const ss=getSitter(currentRoom.sitterStatus||"not_required"),SIc=ss.icon;return(<Card padding="p-3" style={{background:ss.bg,border:`1px solid ${ss.color}40`}}><div className="flex items-center gap-3"><div className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0" style={{background:ss.color,color:"#fff"}}><SIc size={16}/></div><div className="flex-1"><div className="text-[10px] uppercase tracking-wider" style={{color:ss.color,fontWeight:700}}>Patient Sitter</div><div className="text-sm font-semibold mt-0.5" style={{color:T.ink}}>{ss.label}</div></div></div></Card>)})()}
{(currentRoom.riskFlags||[]).length>0&&<Card padding="p-3" style={{background:"#FFFBEB",border:"1.5px solid #D97706"}}><div className="flex items-center gap-1.5 mb-2"><AlertTriangle size={13} style={{color:"#D97706"}}/><span className="text-[11px] font-bold uppercase tracking-wider" style={{color:"#D97706"}}>Risk Flags ({(currentRoom.riskFlags||[]).length})</span></div><div className="flex flex-wrap gap-1">{(currentRoom.riskFlags||[]).map(fid=>{const f=getRisk(fid);if(!f)return null;const FIc=f.icon;return(<span key={fid} className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-bold" style={{background:f.color,color:"#fff"}}><FIc size={10}/>{f.short}</span>)})}
</div></Card>}
